// Solution
function formatQuery(query, projection) {
  let formattedQuery = {}
  for (let field in query) {
    if (query[field] !== undefined && projection[field] === undefined) {
      continue
    }
    if (projection[field] === null) {
      delete query[field]
    } else {
      formattedQuery[field] = query[field]
    }
  }
  return formattedQuery
}

