class Solution:
  def formatQuery(self, query, projection):
    # Remove fields with null values in the projection
    for field in list(query.keys()):
      if projection.get(field) is None:
        del query[field]
    # Remove fields with missing values in the query
    for field in list(query.keys()):
      if field not in projection or projection[field] is None:
        del query[field]
    return query
